CustomField.formula:
IF ( RecordType.DeveloperName == 'en_zenekonsh' ,
  IF ( EN_Alert_BeforeMonth__c != null ,
       ADDMONTHS(en_ukeoityakkouyoteibi__c, -EN_Alert_BeforeMonth__c),
       IF ( en_zyutyuumokuhyougaku__c >= 50000000 ,
            ADDMONTHS(en_ukeoityakkouyoteibi__c, -6),
            ADDMONTHS(en_ukeoityakkouyoteibi__c, -6)
            )
      )
				, null
			)
